sys_script_include.script:
var EQIX_PatchManagement_Utils_Global = Class.create();
EQIX_PatchManagement_Utils_Global.prototype = {
    initialize: function() {},

    getUserTimeZone: function(dateTimeString, timeZone) {
        // Create a GlideDateTime .
        var gdt = new GlideDateTime();

        // Set the time zone for the GlideDateTime object
        gdt.setTimeZone(timeZone);

        // Set the display value of the GlideDateTime object using the date/time string
        // This will interpret the string as being in the specified time zone.
        gdt.setDisplayValue(dateTimeString, "yyyy-MM-dd HH:mm:ss");

        // Get the UTC value
        var utcDateTime = gdt.getValue();

        //Get User Time Zone Value
        var userDateTime = new GlideDateTime(utcDateTime); // UTC
        var localDateTime = userDateTime.getDisplayValue();

        return localDateTime;
    },
    covertTZ: function(dateStr, toTZ) {
        var sz = gs.getProperty('glide.sys.default.tz');
        var tzConvert = new GlideScheduleDateTime(dateStr);
        tzConvert.convertTimeZone(sz, toTZ);
        return tzConvert;
    },

    getNxtPatchDate: function(month, weekday, n) {

        var gdt = new GlideDateTime();
        var currentMonth = gdt.getMonth();
        if (month < currentMonth) {
            gdt.addYears(1);
        }

        var year = gdt.getYear();
        gdt = new GlideDateTime(year + '-' + month + '-01 00:00:00');

        // Find the first occurrence of the weekday

        while (gdt.getDayOfWeekUTC() != weekday) {
            gdt.addDays(1);
        }

        // Move to the nth occurrence
        gdt.addDaysUTC((n - 1) * 7);

        return gdt;
    },

    getLogInUserTimeZone: function() {

        var tz = gs.getUser().getTZ();
        return tz;

    },

    getTZPatchDate: function(localnxtPatchDate, timeZone, pTimeZone) {

        gdt = new GlideDateTime();
        gdt.setDisplayValue(localnxtPatchDate);

        gdt.setTimeZone(timeZone);

        var gdtSP = new GlideDateTime(gdt);
        gdtSP.setTimeZone(pTimeZone);

        return (gdtSP.getDisplayValue());
    },

    iddetails: function() {

        var finalList = [];
        var patchRoutines = [];
        var routinesToExclude = [];

        var ga = new GlideAggregate('x_equi2_patch_mana_m2m_cmdb_ci_patch_routine');
        ga.addEncodedQuery('active_subscription=false^ORcmdb_ci.u_active_flag=false^ORcmdb_ci.install_status!=1');
        ga.groupBy('x_equi2_patch_mana_patch_routine');
        ga.query();

        while (ga.next()) {
            patchRoutines.push(ga.getValue('x_equi2_patch_mana_patch_routine'));
        }

        // gs.info("patch Routine" + patchRoutines);

        // 2) Find routines that also have at least one positive ci
        var gam2m = new GlideAggregate('x_equi2_patch_mana_m2m_cmdb_ci_patch_routine');
        gam2m.addQuery('x_equi2_patch_mana_patch_routine', 'IN', patchRoutines.join(','));
        gam2m.addEncodedQuery('active_subscription=true^cmdb_ci.u_active_flag=true^cmdb_ci.install_status=1');
        gam2m.groupBy('x_equi2_patch_mana_patch_routine');
        gam2m.query();

        while (gam2m.next()) {
            routinesToExclude.push(gam2m.getValue('x_equi2_patch_mana_patch_routine'));
        }


        // 3) contact postive and negative routines
        var excludeSet = {};
        routinesToExclude.forEach(function(r) {
            excludeSet[r] = true;
        });

        var finalRoutines = patchRoutines.filter(function(r) {
            return !excludeSet[r];
        });

        // //Get Patch Routines that HAVE M2M records

        var routinesWithM2M = {};

        var m2mGR = new GlideRecord('x_equi2_patch_mana_m2m_cmdb_ci_patch_routine');
        m2mGR.query();
        while (m2mGR.next()) {
            routinesWithM2M[m2mGR.x_equi2_patch_mana_patch_routine.toString()] = true;
        }

        //Get Patch Routines WITHOUT any M2M records

        var routinesWithoutM2M = [];

        var prGR = new GlideRecord('x_equi2_patch_mana_patch_routine');
        prGR.query();
        while (prGR.next()) {
            var prId = prGR.getUniqueValue();
            if (!routinesWithM2M[prId]) {
                routinesWithoutM2M.push(prId);
            }
        }

        //Merge both result sets (NO duplicates)

        var finalMap = {};
        finalRoutines.concat(routinesWithoutM2M).forEach(function(r) {
            finalMap[r] = true;
        });

        finalList = Object.keys(finalMap);
        return finalList;
    },

    type: 'EQIX_PatchManagement_Utils_Global'
};
